/* Suggested markup: <div class="uiwiki-counterweight-metric-title" tabindex="0"><span>Counterweight Metric Title</span></div> */
.uiwiki-counterweight-metric-title {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-counterweight-metric-title > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: counterweight_metric_title 1.8s ease-in-out infinite alternate;
}
.uiwiki-counterweight-metric-title:hover,
.uiwiki-counterweight-metric-title:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes counterweight_metric_title {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-counterweight-metric-title, .uiwiki-counterweight-metric-title > span { animation: none; transition: none; }
}
